import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';

function ProductDetail({ token }) {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [quantity, setQuantity] = useState(1);
  const [selectedColor, setSelectedColor] = useState('');
  const [selectedSize, setSelectedSize] = useState('');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [selectedImage, setSelectedImage] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    fetchProduct();
  }, [id]);

  const fetchProduct = async () => {
    try {
      const res = await axios.get(`/api/products/${id}`);
      setProduct(res.data);
      setSelectedImage(res.data.media?.featured || `/products/${res.data._id}.jpg`);
      if (res.data.variants && res.data.variants.length > 0) {
        setSelectedColor(res.data.variants[0].color);
        if (res.data.variants[0].sizes && res.data.variants[0].sizes.length > 0) {
          setSelectedSize(res.data.variants[0].sizes[0]);
        }
      }
    } catch (err) {
      setError('Product not found');
    } finally {
      setLoading(false);
    }
  };

  const handleAddToCart = async (e) => {
    e.preventDefault();
    if (!token) {
      navigate('/login');
      return;
    }

    try {
      await axios.post('/api/cart/add',
        { productId: id, quantity: parseInt(quantity), size: selectedSize, color: selectedColor },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setSuccess('Added to cart!');
      setTimeout(() => setSuccess(''), 2000);
    } catch (err) {
      setError('Failed to add to cart');
    }
  };

  if (loading) return <div style={{ padding: '60px 50px', textAlign: 'center', fontFamily: 'Helvetica, Arial, sans-serif' }}>Loading...</div>;
  if (error) return <div style={{ padding: '60px 50px', textAlign: 'center', fontFamily: 'Helvetica, Arial, sans-serif', color: '#d32f2f' }}>{error}</div>;
  if (!product) return <div style={{ padding: '60px 50px', textAlign: 'center', fontFamily: 'Helvetica, Arial, sans-serif', color: '#d32f2f' }}>Product not found</div>;

  const currentVariant = product.variants?.find(v => v.color === selectedColor);
  const sizes = currentVariant?.sizes || [];

  return (
    <div style={{
      display: 'flex',
      gap: '60px',
      padding: '60px 50px',
      backgroundColor: '#fff',
      fontFamily: 'Helvetica, Arial, sans-serif'
    }}>
      {/* Left side - Images */}
      <div style={{ flex: 1 }}>
        {/* Main Image */}
        <div style={{
          aspectRatio: '1000 / 1400',
          backgroundColor: '#f9f9f9',
          marginBottom: '20px',
          overflow: 'hidden',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center'
        }}>
          <img
            src={selectedImage}
            alt={product.name}
            style={{
              width: '100%',
              height: '100%',
              objectFit: 'cover'
            }}
          />
        </div>

        {/* Thumbnail Gallery */}
        {product.media?.gallery && product.media.gallery.length > 0 && (
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(4, 1fr)',
            gap: '10px'
          }}>
            <div
              onClick={() => setSelectedImage(product.media.featured)}
              style={{
                aspectRatio: '1',
                backgroundColor: '#f9f9f9',
                cursor: 'pointer',
                border: selectedImage === product.media.featured ? '1px solid #000' : '1px solid #f0f0f0'
              }}
            >
              <img
                src={product.media.featured}
                alt="Main"
                style={{ width: '100%', height: '100%', objectFit: 'cover' }}
              />
            </div>
            {product.media.gallery.map((img, idx) => (
              <div
                key={idx}
                onClick={() => setSelectedImage(img)}
                style={{
                  aspectRatio: '1',
                  backgroundColor: '#f9f9f9',
                  cursor: 'pointer',
                  border: selectedImage === img ? '1px solid #000' : '1px solid #f0f0f0'
                }}
              >
                <img
                  src={img}
                  alt={`Gallery ${idx}`}
                  style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                />
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Right side - Product Info */}
      <div style={{ flex: 1 }}>
        {/* Product Name */}
        <h1 style={{
          fontSize: '28px',
          fontWeight: '300',
          letterSpacing: '1px',
          color: '#000',
          margin: '0 0 20px 0',
          textTransform: 'uppercase'
        }}>
          {product.name}
        </h1>

        {/* Price */}
        <p style={{
          fontSize: '18px',
          fontWeight: '400',
          letterSpacing: '0.5px',
          color: '#000',
          margin: '0 0 30px 0'
        }}>
          ${product.price}
        </p>

        {/* Description */}
        {product.details?.description && (
          <div style={{
            fontSize: '13px',
            fontWeight: '300',
            lineHeight: '1.8',
            letterSpacing: '0.3px',
            color: '#666',
            marginBottom: '40px'
          }}>
            {product.details.description}
          </div>
        )}

        {/* Materials */}
        {product.details?.materials && product.details.materials.length > 0 && (
          <div style={{
            fontSize: '12px',
            fontWeight: '300',
            letterSpacing: '0.5px',
            color: '#999',
            marginBottom: '30px'
          }}>
            <div style={{ marginBottom: '10px', textTransform: 'uppercase' }}>MATERIALS</div>
            {product.details.materials.map((material, idx) => (
              <div key={idx}>
                {material.type}: {material.value}%
              </div>
            ))}
          </div>
        )}

        {/* Divider */}
        <div style={{
          height: '1px',
          backgroundColor: '#f0f0f0',
          margin: '30px 0'
        }} />

        {/* Form */}
        <form onSubmit={handleAddToCart} style={{ marginTop: '20px' }}>
          {success && (
            <div style={{
              padding: '12px',
              backgroundColor: '#f0f0f0',
              fontSize: '12px',
              color: '#000',
              marginBottom: '20px',
              letterSpacing: '0.5px'
            }}>
              {success}
            </div>
          )}
          {error && (
            <div style={{
              padding: '12px',
              backgroundColor: '#ffebee',
              fontSize: '12px',
              color: '#d32f2f',
              marginBottom: '20px',
              letterSpacing: '0.5px'
            }}>
              {error}
            </div>
          )}

          {/* Color Selection */}
          {product.variants && product.variants.length > 0 && (
            <div style={{ marginBottom: '30px' }}>
              <label style={{
                display: 'block',
                fontSize: '11px',
                fontWeight: '400',
                letterSpacing: '0.5px',
                textTransform: 'uppercase',
                color: '#999',
                marginBottom: '15px'
              }}>
                COLOR: {selectedColor}
              </label>
              <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                {product.variants.map((variant) => (
                  <button
                    key={variant.color}
                    type="button"
                    onClick={() => setSelectedColor(variant.color)}
                    style={{
                      padding: '12px 20px',
                      border: selectedColor === variant.color ? '1px solid #000' : '1px solid #f0f0f0',
                      backgroundColor: '#fff',
                      fontSize: '12px',
                      fontFamily: 'Helvetica, Arial, sans-serif',
                      fontWeight: '300',
                      letterSpacing: '0.5px',
                      color: '#000',
                      cursor: 'pointer',
                      transition: 'all 0.3s'
                    }}
                  >
                    {variant.color}
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Size Selection */}
          {sizes.length > 0 && (
            <div style={{ marginBottom: '30px' }}>
              <label style={{
                display: 'block',
                fontSize: '11px',
                fontWeight: '400',
                letterSpacing: '0.5px',
                textTransform: 'uppercase',
                color: '#999',
                marginBottom: '15px'
              }}>
                SIZE
              </label>
              <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                {sizes.map((size) => (
                  <button
                    key={size}
                    type="button"
                    onClick={() => setSelectedSize(size)}
                    style={{
                      padding: '12px 20px',
                      border: selectedSize === size ? '1px solid #000' : '1px solid #f0f0f0',
                      backgroundColor: '#fff',
                      fontSize: '12px',
                      fontFamily: 'Helvetica, Arial, sans-serif',
                      fontWeight: '300',
                      letterSpacing: '0.5px',
                      color: '#000',
                      cursor: 'pointer',
                      transition: 'all 0.3s'
                    }}
                  >
                    {size}
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Quantity */}
          <div style={{ marginBottom: '30px' }}>
            <label style={{
              display: 'block',
              fontSize: '11px',
              fontWeight: '400',
              letterSpacing: '0.5px',
              textTransform: 'uppercase',
              color: '#999',
              marginBottom: '15px'
            }}>
              QUANTITY
            </label>
            <input
              type="number"
              min="1"
              max="10"
              value={quantity}
              onChange={(e) => setQuantity(e.target.value)}
              style={{
                width: '60px',
                padding: '10px 12px',
                border: '1px solid #f0f0f0',
                fontSize: '13px',
                fontFamily: 'Helvetica, Arial, sans-serif',
                color: '#000'
              }}
            />
          </div>

          {/* Add to Cart Button */}
          <button
            type="submit"
            style={{
              width: '100%',
              padding: '15px',
              backgroundColor: '#000',
              color: '#fff',
              border: 'none',
              fontSize: '12px',
              fontFamily: 'Helvetica, Arial, sans-serif',
              fontWeight: '400',
              letterSpacing: '1px',
              textTransform: 'uppercase',
              cursor: 'pointer',
              transition: 'opacity 0.3s'
            }}
            onMouseEnter={(e) => e.target.style.opacity = '0.8'}
            onMouseLeave={(e) => e.target.style.opacity = '1'}
          >
            Add to Cart
          </button>
        </form>

        {/* Additional Info */}
        {product.details?.care && (
          <div style={{
            marginTop: '50px',
            paddingTop: '30px',
            borderTop: '1px solid #f0f0f0',
            fontSize: '12px',
            fontWeight: '300',
            lineHeight: '1.8',
            letterSpacing: '0.3px',
            color: '#999'
          }}>
            <div style={{ marginBottom: '10px', textTransform: 'uppercase', color: '#000' }}>CARE</div>
            {product.details.care}
          </div>
        )}
      </div>
    </div>
  );
}

export default ProductDetail;
